<template>
<div class="v-popup-wrapper" ref="popup-wrapper">
 <div class="v-popup">
        <div class="v-popup-header">
            <!-- <span>Popup name</span> -->
            <!-- <span
            @click="closePopup"
            >
                cancle
                </span> -->
        </div>
        <div class="v-popup-content">
            <slot></slot>
        </div>
        <div class="v-popup-footer"></div>
    </div>
</div>
   
</template>

<script>
export default {
    name: "v-popup",
    props: {},
    data(){
        return{}
    },
    methods:{
        closePopup(){
            this.$emit('closePopup')
        }
    },
    mounted() {
        let vm = this;
        document.addEventListener('click', function(item){
            if(item.target === vm.$refs['popup-wrapper']) {
                vm.closePopup()
            }
        })
    },
}
</script>

<style >
.v-popup-wrapper{
    /* background-color: rgba(0, 0, 0, 0.3);
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    right: 0;
    left: 0;
    top: 0;
    bottom: 0;
    z-index: 1; */
    position: fixed;
    z-index: 99999;
    top: 0; left: 0; right: 0; bottom: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow-y: auto;
    background-color: rgba(0, 0, 0, .3);
   

}
.v-popup{
    padding: 16px;
    width: 440px;
    height: 545px;
    position: fixed;
    margin-top: 20px;
    background: #fff;
    box-shadow: 0 0 0 17px 0 #e7e7e7e7;
    margin-left: 915px;
    z-index: 10;
    margin-bottom: 125px;
    position: absolute;
      
    max-width: 100vw;
 
}



/* .v-popup-wrapper{
    background-color: rgba(0, 0, 0, 0.3);
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    width: 100%;
    height: 100%;
    z-index: 1;
}
.v-popup{
    padding: 16px;
    width: 440px;
    height: 545px;
    position: fixed;
    background: #fff;
    box-shadow: 0 0 0 17px 0 #e7e7e7e7;
    border:solid;
    margin-left: 460px;
    z-index: 10;
} */
 
</style>




