
<template >

  <div>
    <v-popup 
            v-if="isInfoPopupVisible"
            @closePopup="closeInfoPopup"
            >
            <div class="col">
                <p class="popup-header">{{$t('reg')}}</p>
            </div>
            <div class="col-7">
                <form class="form-login">
                    <label class="form-text" for="username">{{$t('phoneNum')}}:</label>
                    <input class="input-log-in" type="tel" id="username" name="username" value="+380">
                    <label class="form-text" for="pwd">Пароль:</label>
                    <!-- <i class="fa fa-eye-slash"></i> -->
                    <img id="eye" src="static/img/eye.png" alt="eye" >
                    <input class="input-log-in-1" type="password" id="pwd" name="pwd" > 
                      
                    <button class="form-text btn-log-in" type="submit">{{$t('regBtn')}}</button>
                   
                </form>
                
            </div>
            
              <div class="col">
                <p class="form-text-or">{{$t('or')}}</p>
              
            
            
                <p class="form-text popup-header">{{$t('logInHelp')}}</p>
                <div class="icons-wrapper">
                         <div class="log-in-icons">
                    <i class="fa fa-facebook" aria-hidden="true"></i>
                </div>
                 <div class="log-in-icons">
                    <i class="fa fa-google" aria-hidden="true"></i>
                </div>
                </div>
           
               
         
              </div>
      
            
    </v-popup>
          <header>
            <nav id="nav">
               
                <div class="container-header">
                    
                    <div class="row">
                        <div class="col">
                            <ul class="navbar-nav">
                                <div class="dd ">
                                <button id="drop-down" @click="isOpenA = ! isOpenA" >
                                    <img class="logo-category" src="static/img/menu.jpg" alt="enu" />
                                </button>
                                
                       
       
                                <button id="drop-down-word" @click="isOpenA = ! isOpenA" >
                                     {{$t('choseCat')}}
                                </button>
                            </div>
                        <ul class="drop-list" v-show="isOpenA" >
                            <li class="drop-item">Спорт<i class="fa fa-angle-right"></i></li>
                            <li class="drop-item">Поліграфія<i class="fa fa-angle-right"></i></li>
                            <li class="drop-item">Майстри та майстрині<i class="fa fa-angle-right"></i></li>
                             <li class="drop-item">Розваги<i class="fa fa-angle-right"></i></li>
                        </ul>
           
                  
            <li class="nav-link link"> <a href="#" @click="setLocale('ru')">Ру</a>  | <a href="#" @click="setLocale('en')">Укр</a></li>
                        </ul>
                    </div>
                    <div class="col">
                        <div class="logo">
                            <img src="static/img/logo.jpg" alt="logo" />
                        </div>
                            <!-- <v-popup
                                     v-if="isInfoPopupVisible"
                                      @closePopup="closeInfoPopup"
                                     >
                                     <p class="popup-header">Реєстрація</p>
                                     <form>
                                        <label for="username">Номер телефону:</label>
                                        <input type="tel" id="username" name="username" value="+380"

>
                                        <label for="pwd">Пароль:</label>
                                        <input type="password" id="pwd" name="pwd">
                                          <input type="submit" value="Зареєструватись">
                                     </form>
                                </v-popup> -->
                    </div>
                    <div class="col">
                        <ul class="navbar-nav-right">
                           
                            <li class="nav-link">
                                <form class="form-search">
                                    <i class="fa fa-search" aria-hidden="true"></i>
                                    <input class="input-search"  type="search"  aria-label="Search"  />
                                </form>
                               
                            </li>
                            <li>
                                <div class="log-in">
                                <button class="log-in-popup-btn" @click="showPopupInfo">
                                        <img class="user" src="static/img/user.png" alt="log-in" >
                                         <p class="entrance" href="#">{{$t('logIn')}}</p>
                                </button>
                                  

                                     
 
                                    </div>
                                </li>
                            </ul>
                        </div>
                    </div>
                </div>
            </nav>
            <div class="banner">
                <img src="static/img/Banner.png" alt="Banner" />
            </div>
        </header>
   
  </div>
</template>

<script>
import vPopup from '../popup/v-popup'
export default {
    
  name: 'Nav',
  components:{
      vPopup
  },
     data () {
    return {
     isOpenA: false,
     isInfoPopupVisible: false
    
    }
  },
    methods: {
     showPopupInfo(){
         this.isInfoPopupVisible = true;
     },
     closeInfoPopup(){
         this.isInfoPopupVisible = false;
        
     },
     setLocale(locale){
         this.$i18n.locale = locale
     }
    },


 
    
}

</script>

<style scoped>

/* .v-popup-wrapper{
 width: 100%;
 height: 100%;
} */

.over{
    overflow: hidden;
}

.popup-header{
    font-size: 40px;
    margin-bottom: 50px;
    text-align: center;
    margin-top: 30px;
}
.form-text{
    font-size: 14px;
    margin-bottom: 10px;
}
.input-log-in {
    border: none;
    outline: none;
    border-bottom: 1px solid rgba(0, 0, 0, 0.35);
    width: 320px;
    margin-bottom: 25px;
}
.btn-log-in{
    margin-top: 25px;
    border: none;
    outline: none;
    background: #DDDBDB;
    width: 196px;
    height: 50px;
    margin-left: 60px;
        font-family: 'Raleway', sans-serif;
    font-style: normal;
    font-weight: 300;
    font-size: 18px;
    line-height: 21px;
    color: #000;
}
.form-login{
    margin-left: 30px;
}


.form-text-or {
  overflow: hidden;
  position: relative;
  margin: 0;
  text-align: center;
  white-space: nowrap;
  margin-right: 40px;
    margin-left: 40px;
    margin-top: 38px;
}
.form-text-or:before,
.form-text-or:after {
  content: '';
  display: inline-block;
  position: relative;
  top: -1px;
  width: 50%;
  height: 1px;
  vertical-align: middle;
  background: black;
}
.form-text-or:before {
  left: -10px;
  margin-left: -50%;
}
.form-text-or:after {
  left: 10px;
  margin-right: -50%;
}

.log-in-icons{
    margin-top: 7px;
    text-align: center;
    height: 45px;
    width: 45px;
    border: 1px solid #DDDBDB;
    font-size: 20px;
    display: inline-block;
    margin-left: 15px;
    margin-right: 15px;
    padding-top: 10px;
}

.icons-wrapper{
    text-align: center;
}

.input-log-in-1{
        border: none;
    outline: none;
    border-bottom: 1px solid rgba(0, 0, 0, 0.35);
    width: 320px;
    margin-bottom: 25px;
}
#eye {
    height: 20px;
    width: 24px;
    display: inline-block;
    position: absolute;
    margin-top: 17px;
    
    margin-left: 235px;
}

.log-in-popup-btn{
  background: none;
  border: none;
  outline: none;
}
.log-in{
 margin-left: 75px;   
}



</style>




  
  



